sql:
SELECT AVG(credit_score) AS average_credit_score
FROM credit_risk_assessments
WHERE risk_level = 'low';

SELECT credit_score
  FROM credit_risk_assessments
  WHERE risk_level = 'low';

SELECT MAX(credit_score) AS highest_good_credit_score
FROM credit_risk_assessments
WHERE class = 'good';

SELECT loan_id, payment_date, payment_amount, payment_status
FROM loan_payments
WHERE payment_status = 'late';

external_knowledge:
; A credit score is a numerical value that represents an individual's creditworthiness; 
; Risk level refers to the likelihood of a loan applicant defaulting on their loan payments, often categorized as low, medium, or high;
; Employment status and residence since are factors used to assess an applicant's stability and ability to repay the loan;
; Income distribution refers to the relative position of an applicant's income within their class.
